package com.restaurantcraft.block; import com.restaurantcraft.data.DecorType; import net.minecraft.sounds.*; import net.minecraft.world.*; import net.minecraft.world.entity.player.Player; import net.minecraft.world.level.Level; import net.minecraft.world.level.block.Block; import net.minecraft.world.level.block.state.BlockState; import net.minecraft.core.BlockPos; import net.minecraft.world.phys.BlockHitResult; public class DecorBlock extends Block { public final DecorType type; public DecorBlock(DecorType t, Properties p){super(p);type=t;} public InteractionResult use(BlockState s, Level l, BlockPos p, Player pl, InteractionHand h, BlockHitResult hit){ if(type==DecorType.INSTRUMENT){l.playSound(pl,p, SoundEvents.NOTE_BLOCK_PLING.get(), SoundSource.BLOCKS,1,1); return InteractionResult.sidedSuccess(l.isClientSide);} return InteractionResult.PASS;} }
